    continuationNotice,
    clearContinuationNotice: () => setContinuationNotice(null),
    localError,
    clearLocalError: () => setLocalError(null),
    hasRetryableMessage: Boolean(lastMessageRef.current),
    retryLastMessage,
    ...mutation,
  };
}

