  const activeReference = imageContext?.activeReference ?? null;
  const shouldUseActiveReference = requestedReferenceImageUrls.length === 0
    && Boolean(TASK_TYPE_TO_REFERENCE_MODE[taskType])
    && Boolean(activeReference?.url);
