  extraParams: Record<string, unknown> = {},
  variantName?: string | null,
  makePrimary: boolean = true,
  viewedAt?: string | null
): Promise<unknown | null> {

  const { data: parentGen, error: fetchError } = await supabase
    .from('generations')
    .select('*')
    .eq('id', parentGenId)
    .single();

  if (fetchError || !parentGen) {
    throw new CompletionError({
      code: 'parent_generation_lookup_failed',
      context: 'createVariantOnParent',
      recoverable: false,
      message: `Parent generation ${parentGenId} was not available for task ${taskId}`,
      metadata: {
        task_id: taskId,
        parent_generation_id: parentGenId,
      },
      cause: fetchError,
    });
  }

  try {
    const variantParams = {
      ...taskData.params,
      source_task_id: taskId,
      ...extraParams,
    };

    await createVariant(
      supabase,
      parentGen.id,
      publicUrl,
      thumbnailUrl,
      variantParams,
      makePrimary,     // is_primary
      variantType,
      variantName || null,
      viewedAt || null
    );

    // Mark task as generation_created
    await supabase
      .from('tasks')
      .update({ generation_created: true })
      .eq('id', taskId);

    return parentGen;

  } catch (variantErr) {
    throw toCompletionError(variantErr, {
      code: 'parent_variant_creation_failed',
      context: 'createVariantOnParent',
      recoverable: true,
      message: `Failed to create parent variant for task ${taskId}`,
      metadata: {
        task_id: taskId,
        parent_generation_id: parentGenId,
        task_type: taskData.task_type,
      },
    });
  }
}

/**
 * Determines the viewedAt timestamp for a child generation variant.
 * For single-segment cases (only one child under parent), returns current timestamp.
 * For multi-segment cases, returns null.
 *
 * This centralizes the single-segment detection logic that was previously scattered
 * across three different code paths:
 * 1. individual_travel_segment with child_generation_id (SPECIAL CASE 1a)
 * 2. Travel segment matching existing generation at position
 * 3. Standard child generation creation
 *
 * @param supabase - Supabase client
 * @param options - Detection options (check in order of preference)
 * @returns ISO timestamp string if single-segment, null otherwise
 */
export async function getChildVariantViewedAt(
  supabase: SupabaseClient,
  options: {
    // Check 1: Explicit flag from orchestrator detection (fastest)
    taskParams?: { _isSingleSegmentCase?: boolean };
    // Check 2: Count siblings under parent (slower but works for individual segments)
    childGeneration?: { parent_generation_id: string | null; is_child: boolean };
    parentGenerationId?: string;
  }
): Promise<string | null> {
  // Fast path: Check explicit flag first (set during orchestrator detection)
  if (options.taskParams?._isSingleSegmentCase === true) {
    return new Date().toISOString();
  }

  // Slow path: Count siblings to determine if single-segment
  // Used by individual_travel_segment which doesn't go through orchestrator detection

    if (existingGeneration) {
      const generation = await handleRegeneration(
        supabase,
        taskId,
        normalizedTaskData,
        existingGeneration,
        publicUrl,
        thumbnailUrl,
        logger,
      );
      return { status: 'created', generation };
    }

    if (routeParams.basedOn && !routeParams.createAsGeneration) {
      const success = await handleVariantCreation(
        supabase,
        taskId,
        normalizedTaskData,
        routeParams.basedOn,
        publicUrl,
        thumbnailUrl,
      );
      if (success) {
        return { status: 'created', generation: { id: routeParams.basedOn } };
      }
    }

    const handlerContext: GenerationHandlerContext = {
      supabase,
      taskId,
      taskData: normalizedTaskData,
      publicUrl,
      thumbnailUrl: thumbnailUrl || null,
      logger,
      childGenerationId: routeParams.childGenerationId ?? undefined,
      parentGenerationId: routeParams.parentGenerationId ?? undefined,
      childOrder: routeParams.childOrder,
      isSingleItem: routeParams.isSingleItem,
    };

    for (const attempt of classifyGenerationRouteAttempts(routeParams)) {
      const generation = await executeGenerationRouteAttempt(attempt, handlerContext);
      if (generation) {
        return { status: 'created', generation };
      }
    }

    throw new CompletionError({
      code: 'generation_route_no_result',
      context: 'createGenerationFromTask',
      recoverable: false,
      message: `No generation route produced a result for task ${taskId}`,
      metadata: {
        task_id: taskId,
        task_type: normalizedTaskData.task_type,
        route_attempts: classifyGenerationRouteAttempts(routeParams),
      },
    });

  } catch (error) {
    const normalizedError = toCompletionError(error, {
      code: 'generation_completion_failed',
      context: 'createGenerationFromTask',
      recoverable: true,
      message: `Failed to create generation for task ${taskId}`,
      metadata: {
        task_id: taskId,
        task_type: normalizedTaskData.task_type,
      },
    });
    logger?.error("Error creating generation", {
      task_id: taskId,
      error: normalizedError.message,
      error_code: normalizedError.code,
      recoverable: normalizedError.recoverable,
      error_context: normalizedError.context,
      error_metadata: normalizedError.metadata,
    });
    throw normalizedError;
  }
}

/**
 * Handle regeneration case - task already has a generation, create new variant
 */
async function handleRegeneration(
  supabase: SupabaseClient,
  taskId: string,
  taskData: CompletedTaskData,
  existingGeneration: GenerationRef,
  publicUrl: string,
  thumbnailUrl: string | null | undefined,
  logger?: CompletionLogger
): Promise<GenerationRef> {
  logger?.info("Existing generation found - creating regenerated variant", {
    task_id: taskId,
    existing_generation_id: existingGeneration.id,
    action: "create_regenerated_variant"
  });

  const variantParams = {
    ...taskData.params,
    source_task_id: taskId,
    created_from: 'task_completion',
    tool_type: taskData.tool_type,
  };

  await createVariant(
    supabase,
    existingGeneration.id,
    publicUrl,
    thumbnailUrl || null,
    variantParams,
    true,
    'regenerated',
    null
  );

  const { shotId, addInPosition } = extractShotAndPosition(taskData.params);
  if (shotId) {
    await linkGenerationToShot(supabase, shotId, existingGeneration.id, addInPosition);
  }

  const { error: markGenerationCreatedError } = await supabase
    .from('tasks')
    .update({ generation_created: true })
    .eq('id', taskId);

  if (markGenerationCreatedError) {
    throw new CompletionError({
      code: 'regeneration_generation_created_update_failed',
      context: 'handleRegeneration',
      recoverable: true,
      message: `Failed to persist generation_created marker for task ${taskId}`,
      metadata: {
        task_id: taskId,
        existing_generation_id: existingGeneration.id,
      },
      cause: markGenerationCreatedError,
    });
  }

  return existingGeneration;
}

