function createLogger() {
  return {
    setDefaultTaskId: vi.fn(),
    info: vi.fn(),
    warn: vi.fn(),
    error: vi.fn(),
    critical: vi.fn(),
    debug: vi.fn(),
    flush: vi.fn().mockResolvedValue(undefined),
  };
}

function createSupabaseAdmin() {
  const finalEq = vi.fn().mockResolvedValue({ error: null });
  const firstEq = vi.fn().mockReturnValue({ eq: finalEq });
  const update = vi.fn().mockReturnValue({ eq: firstEq });
  const maybeSingle = vi.fn().mockResolvedValue({ error: null });
  const rpc = vi.fn().mockReturnValue({ maybeSingle });
  const from = vi.fn().mockReturnValue({ update });
  return { from, update, firstEq, finalEq, rpc, maybeSingle };
}

describe('completeTaskHandler', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    vi.stubGlobal('Deno', {
      env: {
        get: (key: string) => {
          if (key === 'SUPABASE_SERVICE_ROLE_KEY') return 'service-role-key';
          if (key === 'SUPABASE_URL') return 'https://example.supabase.co';
          return undefined;
        },
      },
    });

    mocks.enforceRateLimit.mockResolvedValue(null);
    mocks.parseCompleteTaskRequest.mockResolvedValue({
      success: true,
      data: {
        taskId: 'task-1',
        mode: 'upload',
        filename: 'out.png',
        requiresOrchestratorCheck: false,
        storagePath: null,
        storagePathTaskId: null,
      },
    });
    mocks.resolveTaskStorageActor.mockResolvedValue({
      ok: true,
      value: {
        isServiceRole: true,
        taskOwnerVerified: true,
        callerId: 'service-role',
        taskUserId: 'user-1',
      },
    });
    mocks.fetchTaskContext.mockResolvedValue({
      id: 'task-1',
      task_type: 'image_generation',
      project_id: 'project-1',
      params: {},
      result_data: {},
      tool_type: 'wan',
      category: 'image',
      content_type: 'image',
      variant_type: null,
    });
    mocks.handleStorageOperations.mockResolvedValue({
      publicUrl: 'https://cdn.example.com/tasks/task-1/out.png',
      objectPath: 'tasks/user-1/task-1/out.png',
      thumbnailUrl: null,
    });
    mocks.validateAndCleanupShotId.mockResolvedValue({
      needsUpdate: false,
      updatedParams: {},
    });
    mocks.extractTimelinePlacement.mockReturnValue(null);
    mocks.createGenerationFromTask.mockResolvedValue({ status: 'created', generation: { id: 'gen-1' } });
    mocks.checkOrchestratorCompletion.mockResolvedValue(undefined);
    mocks.triggerCostCalculationIfNotSubTask.mockResolvedValue({ ok: true });
    mocks.persistCompletionFollowUpIssues.mockResolvedValue({ ok: true });
    mocks.loadTimelineState.mockResolvedValue({
      config: { clips: [] },
      configVersion: 1,
      registry: { assets: {} },
      projectId: 'project-1',
      shotNamesById: {},
    });
    mocks.addMediaClip.mockReturnValue({
      config: { clips: [{ id: 'clip-added', track: 'V1', at: 12.5, asset: 'asset-added', clipType: 'hold', hold: 5 }] },
      result: 'Added media clip clip-added on track V1 at 12.5s.',
    });
    mocks.saveTimelineConfigVersioned.mockResolvedValue(2);
  });

  it('returns bootstrap response when bootstrap fails', async () => {
    mocks.bootstrapEdgeHandler.mockResolvedValue({
      ok: false,
      response: new Response('blocked', { status: 401 }),
    });

    const response = await completeTaskHandler(
      new Request('https://edge.test/complete-task', { method: 'POST' }),
    );

    expect(response.status).toBe(401);
    await expect(response.text()).resolves.toBe('blocked');
  });

  it('returns parse failure response from request parser', async () => {
    const logger = createLogger();
    mocks.bootstrapEdgeHandler.mockResolvedValue({
      ok: true,
      value: {
        supabaseAdmin: createSupabaseAdmin(),
        logger,
        auth: { userId: 'user-1', isServiceRole: false },
      },
    });

    mocks.parseCompleteTaskRequest.mockResolvedValue({
      success: false,
      response: new Response('invalid', { status: 400 }),
    });

    const response = await completeTaskHandler(
      new Request('https://edge.test/complete-task', { method: 'POST' }),
    );

    expect(response.status).toBe(400);
    await expect(response.text()).resolves.toBe('invalid');
  });

  it('completes task and returns success payload', async () => {
    const logger = createLogger();
    const supabaseAdmin = createSupabaseAdmin();
    mocks.bootstrapEdgeHandler.mockResolvedValue({
      ok: true,
      value: {
        supabaseAdmin,
        logger,
        auth: { userId: null, isServiceRole: true },
      },
    });

    const response = await completeTaskHandler(
      new Request('https://edge.test/complete-task', { method: 'POST' }),
    );

    );

    expect(response.status).toBe(200);
    await expect(response.json()).resolves.toEqual({
      success: true,
      public_url: 'https://cdn.example.com/tasks/task-1/out.png',
      thumbnail_url: null,
      follow_up: { status: 'ok', issues: [] },
      message: 'Task completed and file uploaded successfully',
    });

    expect(logger.setDefaultTaskId).toHaveBeenCalledWith('task-1');
    expect(mocks.resolveTaskStorageActor).toHaveBeenCalled();
    expect(mocks.fetchTaskContext).toHaveBeenCalled();
    expect(mocks.createGenerationFromTask).toHaveBeenCalled();
    expect(supabaseAdmin.from).toHaveBeenCalledWith('tasks');
    expect(logger.flush).toHaveBeenCalled();
  });

  it('preserves structured CompletionError details when generation creation fails', async () => {
    const logger = createLogger();
    const supabaseAdmin = createSupabaseAdmin();
    mocks.bootstrapEdgeHandler.mockResolvedValue({
      ok: true,
      value: {
        supabaseAdmin,
        logger,
        auth: { userId: null, isServiceRole: true },
      },
    });
    mocks.createGenerationFromTask.mockRejectedValue(
      new CompletionError({
        code: 'generation_route_no_result',
        message: 'No generation route produced a result',
        context: 'createGenerationFromTask',
        recoverable: false,
        metadata: { task_id: 'task-1' },
      }),
    );

    const response = await completeTaskHandler(
      new Request('https://edge.test/complete-task', { method: 'POST' }),
    );

    expect(response.status).toBe(500);
    await expect(response.json()).resolves.toEqual({
      message: 'No generation route produced a result',
      errorCode: 'generation_route_no_result',
      recoverable: false,
    });
    expect(logger.error).toHaveBeenCalledWith('Generation creation failed', expect.objectContaining({
      error_code: 'generation_route_no_result',
      recoverable: false,
      error_context: 'createGenerationFromTask',
      error_metadata: { task_id: 'task-1' },
    }));
    expect(mocks.markTaskFailed).toHaveBeenCalledWith(
      supabaseAdmin,
      'task-1',
      'Generation creation failed [generation_route_no_result]: No generation route produced a result',
    );
    expect(mocks.completeTaskErrorResponse).toHaveBeenCalledWith(
      'No generation route produced a result',
      500,
      'generation_route_no_result',
      { recoverable: false },
    );
  });

  it('wraps plain generation failures with the generic internal server response', async () => {
    const logger = createLogger();
    const supabaseAdmin = createSupabaseAdmin();
    mocks.bootstrapEdgeHandler.mockResolvedValue({
      ok: true,
      value: {
        supabaseAdmin,
        logger,
        auth: { userId: null, isServiceRole: true },
      },
    });
    mocks.createGenerationFromTask.mockRejectedValue(new Error('boom'));

    const response = await completeTaskHandler(
      new Request('https://edge.test/complete-task', { method: 'POST' }),
    );

    expect(response.status).toBe(500);
    await expect(response.json()).resolves.toEqual({
      message: 'Internal server error',
      errorCode: 'internal_server_error',
      recoverable: undefined,
    });
    expect(logger.error).toHaveBeenCalledWith('Generation creation failed', expect.objectContaining({
      error: 'boom',
      error_code: 'generation_completion_failed',
      recoverable: true,
    }));
    expect(mocks.markTaskFailed).toHaveBeenCalledWith(
      supabaseAdmin,
      'task-1',
      'Generation creation failed: boom',
    );
  });

  it('attempts timeline insertion when placement intent is present in task params', async () => {
    const logger = createLogger();
    const supabaseAdmin = createSupabaseAdmin();
    const timelinePlacement = {
      timeline_id: 'timeline-1',
      source_clip_id: 'clip-source-1',
      target_track: 'V1',
      insertion_time: 12.5,
      intent: 'after_source' as const,
    };

    mocks.bootstrapEdgeHandler.mockResolvedValue({
      ok: true,
      value: {
        supabaseAdmin,
        logger,
        auth: { userId: null, isServiceRole: true },
      },
    });
    mocks.fetchTaskContext.mockResolvedValue({
      id: 'task-1',
      task_type: 'image_generation',
      project_id: 'project-1',
      params: { timeline_placement: timelinePlacement },
      result_data: {},
      tool_type: 'wan',
      category: 'image',
      content_type: 'image',
      variant_type: null,
    });
    mocks.extractTimelinePlacement.mockReturnValue(timelinePlacement);

    const response = await completeTaskHandler(
      new Request('https://edge.test/complete-task', { method: 'POST' }),
    );

    expect(response.status).toBe(200);
    expect(mocks.extractTimelinePlacement).toHaveBeenCalledWith({ timeline_placement: timelinePlacement });
    expect(mocks.loadTimelineState).toHaveBeenCalledWith(supabaseAdmin, 'timeline-1');
    expect(supabaseAdmin.rpc).toHaveBeenCalledWith('upsert_asset_registry_entry', expect.objectContaining({
      p_timeline_id: 'timeline-1',
      p_entry: expect.objectContaining({
        file: 'https://cdn.example.com/tasks/task-1/out.png',
        generationId: 'gen-1',
        type: 'image/png',
      }),
    }));

    const rpcArgs = supabaseAdmin.rpc.mock.calls[0]?.[1] as { p_asset_id: string };
    expect(mocks.addMediaClip).toHaveBeenCalledWith(
      { clips: [] },
      expect.objectContaining({
        assets: expect.objectContaining({
          [rpcArgs.p_asset_id]: expect.objectContaining({
            file: 'https://cdn.example.com/tasks/task-1/out.png',
            generationId: 'gen-1',
          }),
        }),
      }),
      {
        track: 'V1',
        at: 12.5,
        assetKey: rpcArgs.p_asset_id,
        mediaType: 'image',
      },
    );
    expect(mocks.saveTimelineConfigVersioned).toHaveBeenCalledWith(
      supabaseAdmin,
      'timeline-1',
      1,
      expect.objectContaining({
        clips: expect.any(Array),
      }),
    );
    expect(mocks.persistCompletionFollowUpIssues).not.toHaveBeenCalled();
  });

  it('still completes successfully when timeline insertion fails after generation creation', async () => {
    const logger = createLogger();
    const supabaseAdmin = createSupabaseAdmin();
    const timelinePlacement = {
      timeline_id: 'timeline-1',
      source_clip_id: 'clip-source-1',
      target_track: 'V1',
      insertion_time: 12.5,
      intent: 'after_source' as const,
    };

    mocks.bootstrapEdgeHandler.mockResolvedValue({
      ok: true,
      value: {
        supabaseAdmin,
        logger,
        auth: { userId: null, isServiceRole: true },
      },
    });
    mocks.fetchTaskContext.mockResolvedValue({
      id: 'task-1',
      task_type: 'image_generation',
      project_id: 'project-1',
      params: { timeline_placement: timelinePlacement },
      result_data: {},
      tool_type: 'wan',
      category: 'image',
      content_type: 'image',
      variant_type: null,
    });
    mocks.extractTimelinePlacement.mockReturnValue(timelinePlacement);
    mocks.addMediaClip.mockReturnValue({
      result: 'Track V1 does not exist.',
    });

    const response = await completeTaskHandler(
      new Request('https://edge.test/complete-task', { method: 'POST' }),
    );

    expect(response.status).toBe(200);
    await expect(response.json()).resolves.toEqual({
      success: true,
      public_url: 'https://cdn.example.com/tasks/task-1/out.png',
      thumbnail_url: null,
      follow_up: {
        status: 'degraded',
        issues: [{
          step: 'timeline_placement',
          code: 'timeline_placement_failed',
          message: 'Track V1 does not exist.',
        }],
      },
      message: 'Task completed with follow-up warnings',
    });
    expect(mocks.saveTimelineConfigVersioned).not.toHaveBeenCalled();
    expect(mocks.persistCompletionFollowUpIssues).toHaveBeenCalledWith(
      supabaseAdmin,
      'task-1',
      {},
      [{
        step: 'timeline_placement',
        code: 'timeline_placement_failed',
        message: 'Track V1 does not exist.',
      }],
    );
    expect(logger.error).toHaveBeenCalledWith('Timeline placement follow-up failed', expect.objectContaining({
      generation_id: 'gen-1',
      timeline_placement: timelinePlacement,
    }));
    expect(mocks.markTaskFailed).not.toHaveBeenCalled();
  });
});

  // 10) Validate shot references and update params if needed
  try {
    let updatedParams = { ...taskContext.params };
    let needsParamsUpdate = false;

    // Validate and cleanup invalid shot_id references
    const shotValidation = await validateAndCleanupShotId(supabaseAdmin, updatedParams, taskContext.tool_type);
    if (shotValidation.needsUpdate) {
      needsParamsUpdate = true;
      updatedParams = shotValidation.updatedParams;
    }

    // Add thumbnail URL if available
    if (thumbnailUrl) {
      needsParamsUpdate = true;
      updatedParams = completeTaskParams.setThumbnailInParams(updatedParams, taskContext.task_type, thumbnailUrl);
    }

    if (needsParamsUpdate) {
      await supabaseAdmin.from("tasks").update({ params: updatedParams }).eq("id", taskIdString);

      // Keep in-memory context in sync so downstream steps (generation creation) use updated params
      taskContext.params = updatedParams;
    }
  } catch (validationError) {
    logger.warn("Validation follow-up failed; continuing completion flow", {
      task_id: taskIdString,
      error: toErrorMessage(validationError),
    });
    completionFollowUpIssues.push({
      step: 'validation',
      code: 'validation_follow_up_failed',
      message: toErrorMessage(validationError),
    });
    // Continue anyway - don't fail task completion due to validation errors
  }

  // 11) Create generation (if applicable)
  const CREATE_GENERATION_IN_EDGE = Deno.env.get("CREATE_GENERATION_IN_EDGE") !== "false";
  let createdGenerationId: string | null = null;
  let completionAssetRef: CompletionAssetRef | null = null;
  if (CREATE_GENERATION_IN_EDGE) {
    try {
      const generationOutcome = await createGenerationFromTask(
        supabaseAdmin,
        taskContext.id,
        {
          id: taskContext.id,
          task_type: taskContext.task_type,
          project_id: taskContext.project_id,
          params: taskContext.params,
          tool_type: taskContext.tool_type,
          content_type: taskContext.content_type,
          variant_type: taskContext.variant_type,
          category: taskContext.category,
        },
        publicUrl,
        thumbnailUrl,
        logger,
        completionAuthContext,
      );

      if (generationOutcome.status === 'skipped') {
        logger.info('Generation creation skipped', {
          task_id: taskContext.id,
          reason: generationOutcome.reason,
        });
      } else {
        completionAssetRef = generationOutcome.completionAsset;
        const generationId = typeof generationOutcome.generation?.id === 'string'
          && generationOutcome.generation.id.length > 0
          ? generationOutcome.generation.id
          : null;
        createdGenerationId = generationId;

        if (!generationId) {
          logger.warn('Generation creation returned no generation id; skipping timeline placement', {
            task_id: taskContext.id,
          });
        } else {
          try {
            await applyCompletedGenerationTimelinePlacement(
              supabaseAdmin as unknown as TimelineSupabaseAdmin,
              {
                taskId: taskContext.id,
                params: taskContext.params,
                contentType: taskContext.content_type,
                generationId,
                publicUrl,
                thumbnailUrl: thumbnailUrl ?? null,
                filename: parsedRequest.filename,
                logger,
              },
            );
          } catch (timelinePlacementError) {
            const message = toErrorMessage(timelinePlacementError);
            logger.error("Timeline placement follow-up failed", {
              task_id: taskContext.id,
              generation_id: generationId,
              error: message,
              timeline_placement: completeTaskParams.extractTimelinePlacement?.(taskContext.params) ?? null,
            });
            completionFollowUpIssues.push({
              step: 'timeline_placement',
              code: 'timeline_placement_failed',
              message,
            });
          }
        }
      }
      void completionAssetRef;
    } catch (genErr: unknown) {
      const normalizedError = genErr instanceof CompletionError ? genErr : null;
      const msg = toErrorMessage(genErr);
      logger.error("Generation creation failed", {
        error: msg,
        error_code: normalizedError?.code ?? 'generation_completion_failed',
        recoverable: normalizedError?.recoverable ?? true,
        error_context: normalizedError?.context,
        error_metadata: normalizedError?.metadata,
      });
      await markTaskFailed(
        supabaseAdmin,
        taskIdString,
        normalizedError
          ? `Generation creation failed [${normalizedError.code}]: ${normalizedError.message}`
          : `Generation creation failed: ${msg}`,
      );
      await logger.flush();
      return completeTaskErrorResponse(
        normalizedError?.message ?? "Internal server error",
        500,
        normalizedError?.code ?? 'internal_server_error',
        normalizedError ? { recoverable: normalizedError.recoverable } : undefined,
      );
    }
  }

  // 12) Update task to Complete
  // Use output_location override if provided (e.g., JSON metadata from transition_only mode),
  // otherwise fall back to the storage public URL
  const finalOutputLocation = parsedRequest.outputLocationOverride || publicUrl;
  const { error: dbError } = await supabaseAdmin.from("tasks").update({
    status: "Complete",
    output_location: finalOutputLocation,
    generation_processed_at: new Date().toISOString()
  }).eq("id", taskIdString).eq("status", "In Progress");

  if (dbError) {
    const dbMsg = toErrorMessage(dbError);
    logger.error("Database update failed", {
      task_id: taskIdString,
      error: dbMsg,
    });
    await markTaskFailed(supabaseAdmin, taskIdString, `Task completion DB update failed: ${dbMsg}`);
    await logger.flush();
    await cleanupFile(supabaseAdmin, objectPath);
    return completeTaskErrorResponse("Internal server error", 500);
  }

  // 13) Check orchestrator completion (for segment tasks) - uses task context
  try {
    await checkOrchestratorCompletion(
      {
        supabase: supabaseAdmin,
        taskIdString,
        completedTask: taskContext, // Pass context instead of fetching again
        publicUrl,
        supabaseUrl,
        serviceKey,
        authContext: completionAuthContext,
        logger,
      },
    );
  } catch (orchErr) {
    logger.warn("Orchestrator completion follow-up failed", {
      task_id: taskIdString,
      error: toErrorMessage(orchErr),
    });
    completionFollowUpIssues.push({
      step: 'orchestrator_completion',
      code: 'orchestrator_follow_up_failed',
      message: toErrorMessage(orchErr),
    });
  }

  // 14) Calculate cost (service role only)
  if (isServiceRole) {
    const billingResult = await triggerCostCalculationIfNotSubTask(
      supabaseAdmin,
      supabaseUrl,
      serviceKey,
      taskIdString,
    );
    if (!billingResult.ok) {
      logger.warn("Cost calculation follow-up failed", {
        task_id: taskIdString,
        billing_result: billingResult,
      });
      completionFollowUpIssues.push({
        step: 'cost_calculation',
        code: billingResult.errorCode || 'cost_calculation_follow_up_failed',
        message: billingResult.message || 'Cost calculation follow-up failed',
      });
    }
  }

  if (completionFollowUpIssues.length > 0) {
    const persistenceResult = await persistCompletionFollowUpIssues(
      supabaseAdmin,
      taskIdString,
      taskContext.result_data,
      completionFollowUpIssues,
    );
    if (!persistenceResult.ok) {
      logger.error("Failed to persist completion follow-up issues", {
        task_id: taskIdString,
        error: persistenceResult.error instanceof Error
          ? persistenceResult.error.message
          : String(persistenceResult.error),
      });
      completionFollowUpIssues.push({
        step: 'follow_up_persistence',
        code: 'completion_follow_up_persistence_failed',
        message: persistenceResult.error instanceof Error
          ? persistenceResult.error.message
          : String(persistenceResult.error),
      });
    }
  }

  // 15) Return success
  const responseData = {
    success: true,
    public_url: publicUrl,
    thumbnail_url: thumbnailUrl,
    follow_up: completionFollowUpIssues.length === 0
      ? { status: 'ok' as const, issues: [] as CompletionFollowUpIssue[] }
      : { status: 'degraded' as const, issues: completionFollowUpIssues },
    message: completionFollowUpIssues.length === 0
      ? "Task completed and file uploaded successfully"
      : "Task completed with follow-up warnings",
  };

  logger.info("Task completed successfully", { 
    task_id: taskIdString,
    output_location: publicUrl,
    generation_id: createdGenerationId,
    has_thumbnail: !!thumbnailUrl,
    follow_up_issue_count: completionFollowUpIssues.length,
  });
  await logger.flush();

  return jsonResponse(responseData, 200);

} catch (error: unknown) {
  const errMsg = toErrorMessage(error);
  logger.critical("Unexpected error", {
    task_id: taskIdString,
    error: errMsg,

export type TimelineEffect = {
  fade_in?: number;
  fade_out?: number;
};

export type ParameterType =
  | 'number'
  | 'select'
  | 'boolean'
  | 'color'
  | 'audio-binding';

export type AudioBindingValue = {
  source: 'bass' | 'mid' | 'treble' | 'amplitude';
  min: number;
  max: number;
};

export type ParameterOption = {
  label: string;
  value: string;
};

export type ParameterDefinition = {
  name: string;
  label: string;
  description: string;
  type: ParameterType;
  default?: number | string | boolean | AudioBindingValue;
  min?: number;
  max?: number;
  step?: number;
  options?: ParameterOption[];
};

export type ParameterSchema = ParameterDefinition[];

export type TrackKind = 'visual' | 'audio';
export type TrackFit = 'cover' | 'contain' | 'manual';
export type TrackBlendMode =
  | 'normal'
  | 'multiply'
  | 'screen'
  | 'overlay'
  | 'darken'
  | 'lighten'
  | 'soft-light'
  | 'hard-light';
export type ClipType = 'media' | 'hold' | 'text' | 'effect-layer';

export type TrackDefinition = {
  id: string;
  kind: TrackKind;
  label: string;
  scale?: number;
  fit?: TrackFit;
  opacity?: number;
  volume?: number;
  muted?: boolean;
  blendMode?: TrackBlendMode;
};

export type ClipEntrance = {
  type: string;
  duration: number;
  intensity?: number;
  params?: Record<string, unknown>;
};

export type ClipExit = {
  type: string;
  duration: number;
  intensity?: number;
  params?: Record<string, unknown>;
};

export type ClipContinuous = {
  type: string;
  intensity?: number;
  params?: Record<string, unknown>;
};

export type ClipTransition = {
  type: string;
  duration: number;
};

export type TextAlignment = 'left' | 'center' | 'right';

export type TextClipData = {
  content: string;
  fontFamily?: string;
  fontSize?: number;
  color?: string;
  align?: TextAlignment;
  bold?: boolean;
  italic?: boolean;
};

export type TimelineClip = {
  id: string;
  at: number;
  track: string;
  clipType?: ClipType;
  asset?: string;
  from?: number;
  to?: number;
  speed?: number;
  hold?: number;
  volume?: number;
  x?: number;
  y?: number;
  width?: number;
  height?: number;
  cropTop?: number;
  cropBottom?: number;
  cropLeft?: number;
