function normalizePathLora(value: unknown): AgentPathLora | null {
  if (!isRecord(value)) {
    return null;
  }

  const path = asTrimmedString(value.path);
  const strength = asOptionalNumber(value.strength);
  if (!path || strength === undefined) {
    return null;
