  if (!id || !resourceId) {
    return null;
  }

  return {
    id,
    resourceId,
    referenceMode: asReferenceMode(value.referenceMode),
    styleReferenceStrength: asOptionalNumber(value.styleReferenceStrength),
    subjectStrength: asOptionalNumber(value.subjectStrength),
